class TradeViewController: UIViewController {
    
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var buyButton: UIButton!
    @IBOutlet weak var sellButton: UIButton!
    
    let apiClient = APIClient()
    var portfolioManager = PortfolioManager()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        buyButton.isEnabled = false
        sellButton.isEnabled = false
        
        stockSymbolTextField.addTarget(self, action: #selector(textFieldDidChange(_:)), for: .editingChanged)
        quantityTextField.addTarget(self, action: #selector(textFieldDidChange(_:)), for: .editingChanged)
    }
    
    @objc func textFieldDidChange(_ textField: UITextField) {
        if let symbol = stockSymbolTextField.text, !symbol.isEmpty,
           let quantityString = quantityTextField.text, let quantity = Int(quantityString), quantity > 0 {
            buyButton.isEnabled = true
            sellButton.isEnabled = true
        } else {
            buyButton.isEnabled = false
            sellButton.isEnabled = false
        }
    }
    
    @IBAction func buyButtonTapped(_ sender: UIButton) {
        guard let symbol = stockSymbolTextField.text, !symbol.isEmpty,
              let quantityString = quantityTextField.text, let quantity = Int(quantityString), quantity > 0 else {
            return
        }
        
        apiClient.executeTrade(symbol: symbol, quantity: quantity, type: .buy) { result in
            switch result {
            case .success(let trade):
                self.portfolioManager.updatePortfolio(trade)
