class APIClient {
    func executeTrade(symbol: String, quantity: Int, type: TradeType, completion: @escaping (Result<Trade, Error>) -> Void) {
        let url = "https://api.example.com/trade"
        let parameters: [String: Any] = [
            "symbol": symbol,
            "quantity": quantity,
            "type": type.rawValue
        ]
        
        Alamofire.request(url, method: .post, parameters: parameters, encoding: JSONEncoding.default, headers: nil).responseJSON { response in
            switch response.result {
            case .success(let value):
                let json = JSON(value)
                if let tradeData = json["trade"].dictionary {
                    let trade = Trade(data: tradeData)
                    completion(.success(trade))
                } else {
                    completion(.failure(NSError(domain: "", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid response"])))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
}

enum TradeType: String {
    case buy
    case sell
}

class Trade {
    let symbol: String
    let quantity: Int
    let type: TradeType
    
    init(data: [String: Any]) {
        self.symbol = data["symbol"] as! String
        self.quantity = data["quantity"] as! Int
        self.type = TradeType(rawValue: data["type"] as! String)!
    }
}

class PortfolioManager {
    var portfolio: [Trade] = []
    
    func updatePortfolio(_ trade: Trade) {
        if let index = portfolio.firstIndex(where: { $0.symbol == trade.symbol && $0.type == trade.type }) {
            portfolio[index].quantity += trade.quantity
        } else {
            portfolio.append(trade)
        }
    }
}